1	<!DOCTYPE html>
2	<html lang="en">
3	
4	<head>
5	    <meta charset="UTF-8">
6	    <title>Vitaliy Hlynianyi-Zhuk — CV</title>
7	    <style>
8	        body,
9	        h1,
10	        h2,
11	        h3,
12	        p,
13	        li,
14	        a {
15	            font-family: Arial, Helvetica, sans-serif !important;
16	        }
17	
18	        /* ── Recruiter Banner ── */
19	        @media print {
20	            #recruiter-banner, #banner-spacer { display: none !important; }
21	        }
22	
23	        #recruiter-banner {
24	            position: fixed;
25	            top: 0; left: 0; right: 0;
26	            z-index: 9999;
27	            font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
28	        }
29	
30	        #banner-strip {
31	            background: linear-gradient(135deg, #0d1b2a 0%, #1b2a3b 60%, #0f3460 100%);
32	            color: #fff;
33	            padding: 10px 20px;
34	            display: flex;
35	            align-items: center;
36	            justify-content: space-between;
37	            cursor: pointer;
38	            border-bottom: 2px solid #e94560;
39	            user-select: none;
40	            transition: background 0.2s;
41	        }
42	        #banner-strip:hover { background: linear-gradient(135deg, #162030 0%, #22334a 60%, #1a4a80 100%); }
43	
44	        #banner-strip-left { display: flex; align-items: center; gap: 10px; }
45	        #banner-strip-icon { font-size: 18px; }
46	        #banner-strip-title { font-weight: 700; font-size: 12px; letter-spacing: 1.5px; color: #fff; }
47	        #banner-strip-sub { font-size: 11px; opacity: 0.55; margin-left: 4px; }
48	        #banner-strip-right { display: flex; align-items: center; gap: 8px; }
49	        #banner-hint { font-size: 10px; opacity: 0.5; letter-spacing: 0.5px; }
50	        #banner-arrow {
51	            font-size: 12px;
52	            display: inline-block;
53	            transition: transform 0.35s cubic-bezier(.4,0,.2,1);
54	            color: #e94560;
55	        }
56	
57	        #banner-panel {
58	            background: #0d1b2a;
59	            max-height: 0;
60	            overflow: hidden;
61	            transition: max-height 0.42s cubic-bezier(.4,0,.2,1);
62	            border-bottom: 2px solid #e94560;
63	        }
64	        #banner-panel.open { max-height: 33vh; }
65	
66	        #banner-inner {
67	            padding: 14px 20px 16px;
68	            height: calc(33vh - 36px);
69	            display: flex;
70	            flex-direction: column;
71	            gap: 10px;
72	            box-sizing: border-box;
73	        }
74	
75	        #banner-toolbar {
76	            display: flex;
77	            align-items: center;
78	            gap: 8px;
79	            flex-shrink: 0;
80	        }
81	        #banner-toolbar-label {
82	            font-size: 10px;
83	            letter-spacing: 1px;
84	            color: #7a9bbf;
85	            text-transform: uppercase;
86	            margin-right: 4px;
87	        }
88	
89	        .blang-btn {
90	            background: transparent;
91	            border: 1px solid #e94560;
92	            color: #c0c8d8;
93	            padding: 4px 13px;
94	            border-radius: 4px;
95	            cursor: pointer;
96	            font-size: 11px;
97	            font-weight: 600;
98	            letter-spacing: 0.5px;
99	            transition: background 0.15s, color 0.15s;
100	            font-family: inherit;
101	        }
102	        .blang-btn:hover { background: rgba(233,69,96,0.15); }
103	        .blang-btn.active { background: #e94560; color: #fff; border-color: #e94560; }
104	
105	        #banner-copy-btn {
106	            margin-left: auto;
107	            background: #e94560;
108	            border: none;
109	            color: #fff;
110	            padding: 5px 16px;
111	            border-radius: 4px;
112	            cursor: pointer;
113	            font-size: 12px;
114	            font-weight: 600;
115	            display: flex;
116	            align-items: center;
117	            gap: 6px;
118	            transition: background 0.15s, transform 0.1s;
119	            font-family: inherit;
120	        }
121	        #banner-copy-btn:hover { background: #c73352; }
122	        #banner-copy-btn:active { transform: scale(0.97); }
123	        #banner-copy-btn.copied { background: #2e7d52; }
124	
125	        #banner-prompt-area {
126	            flex: 1;
127	            overflow-y: auto;
128	            font-size: 11.5px;
129	            line-height: 1.65;
130	            white-space: pre-wrap;
131	            font-family: 'SF Mono', 'Fira Code', 'Courier New', monospace;
132	            background: rgba(255,255,255,0.04);
133	            border: 1px solid rgba(255,255,255,0.08);
134	            border-radius: 6px;
135	            padding: 10px 14px;
136	            color: #a8bdd4;
137	            scrollbar-width: thin;
138	            scrollbar-color: #e94560 transparent;
139	        }
140	        #banner-prompt-area::-webkit-scrollbar { width: 4px; }
141	        #banner-prompt-area::-webkit-scrollbar-thumb { background: #e94560; border-radius: 2px; }
142	    </style>
143	</head>
144	
145	<body style="font-family: Arial, sans-serif; font-size: 14px; color: #000; line-height: 1.4; margin: 0; padding: 20px; padding-top: 58px;">
146	
147	    <!-- ── Recruiter Banner ── -->
148	    <div id="recruiter-banner">
149	        <div id="banner-strip" onclick="toggleBanner()">
150	            <div id="banner-strip-left">
151	                <span id="banner-strip-icon">🎯</span>
152	                <span id="banner-strip-title">FOR RECRUITERS</span>
153	                <span id="banner-strip-sub">— AI Resume Analysis Prompt</span>
154	            </div>
155	            <div id="banner-strip-right">
156	                <span id="banner-hint">Click to expand</span>
157	                <span id="banner-arrow">▼</span>
158	            </div>
159	        </div>
160	        <div id="banner-panel">
161	            <div id="banner-inner">
162	                <div id="banner-toolbar">
163	                    <span id="banner-toolbar-label">Language</span>
164	                    <button class="blang-btn active" id="bbtn-en" onclick="bannerSetLang('en'); event.stopPropagation()">EN</button>
165	                    <button class="blang-btn" id="bbtn-ua" onclick="bannerSetLang('ua'); event.stopPropagation()">UA</button>
166	                    <button id="banner-copy-btn" onclick="bannerCopy(); event.stopPropagation()">
167	                        <span id="banner-copy-icon">📋</span>
168	                        <span id="banner-copy-text">Copy Prompt</span>
169	                    </button>
170	                </div>
171	                <div id="banner-prompt-area"></div>
172	            </div>
173	        </div>
174	    </div>
175	
176	    <script>
177	    (function () {
178	        var RESUME_URL = 'https://hlyniany.github.io/mycv/cv.resume.json';
179	
180	        var PROMPTS = {
181	            en: 'You are an expert technical recruiter assistant and resume analyst.\n\nI will provide you with:\n1. A JSON Resume (fetched from URL below)\n2. A job description (I will paste it after this prompt)\n\n**Resume JSON URL:** ' + RESUME_URL + '\n\n**Your task:**\n1. Fetch and parse the JSON Resume from the URL above\n2. Read the job description I paste below\n3. Analyze the match between the candidate\'s profile and the role\n4. Output a structured report:\n\n---\n## Match Analysis\n\n### ✅ Strong matches\n[Skills, experience, keywords that directly align]\n\n### ⚠️ Partial matches\n[Areas where candidate has adjacent but not exact experience]\n\n### ❌ Gaps\n[Requirements not covered by the resume]\n\n### 🏆 Overall fit score\n[X/10 with one-sentence rationale]\n\n### 💬 Suggested talking points for screening call\n[3–5 specific questions based on gaps or ambiguities]\n\n---\n\n**Job description:**\n[PASTE JOB DESCRIPTION HERE]',
182	            ua: 'Ти — експерт з технічного рекрутингу та аналізу резюме.\n\nЯ надам тобі:\n1. JSON Resume (за URL нижче)\n2. Опис вакансії (вставлю після цього промту)\n\n**URL резюме у форматі JSON:** ' + RESUME_URL + '\n\n**Твоє завдання:**\n1. Завантажити та розпарсити JSON Resume за вказаним URL\n2. Прочитати опис вакансії, який я вставлю нижче\n3. Проаналізувати відповідність профілю кандидата та вимог ролі\n4. Сформувати структурований звіт:\n\n---\n## Аналіз відповідності\n\n### ✅ Сильні збіги\n[Навички, досвід, ключові слова, які прямо відповідають вимогам]\n\n### ⚠️ Часткові збіги\n[Сфери, де кандидат має суміжний, але не точний досвід]\n\n### ❌ Прогалини\n[Вимоги, які не покриті резюме]\n\n### 🏆 Загальна оцінка відповідності\n[X/10 з одним реченням обґрунтування]\n\n### 💬 Рекомендовані питання для скринінгового дзвінка\n[3–5 конкретних питань на основі прогалин або неоднозначностей]\n\n---\n\n**Опис вакансії:**\n[ВСТАВТЕ ОПИС ВАКАНСІЇ ТУТ]'
183	        };
184	
185	        var currentLang = 'en';
186	        var isOpen = false;
187	
188	        function init() {
189	            document.getElementById('banner-prompt-area').textContent = PROMPTS['en'];
190	        }
191	
192	        window.toggleBanner = function () {
193	            isOpen = !isOpen;
194	            var panel = document.getElementById('banner-panel');
195	            var arrow = document.getElementById('banner-arrow');
196	            var hint = document.getElementById('banner-hint');
197	            var body = document.body;
198	
199	            panel.classList.toggle('open', isOpen);
200	            arrow.style.transform = isOpen ? 'rotate(180deg)' : '';
201	            hint.textContent = isOpen ? 'Click to collapse' : 'Click to expand';
202	
203	            var stripH = document.getElementById('banner-strip').offsetHeight;
204	            var panelH = isOpen ? Math.round(window.innerHeight * 0.33) : 0;
205	            body.style.paddingTop = (stripH + panelH + 4) + 'px';
206	        };
207	
208	        window.bannerSetLang = function (lang) {
209	            currentLang = lang;
210	            document.getElementById('banner-prompt-area').textContent = PROMPTS[lang];
211	            document.getElementById('bbtn-en').classList.toggle('active', lang === 'en');
212	            document.getElementById('bbtn-ua').classList.toggle('active', lang === 'ua');
213	        };
214	
215	        window.bannerCopy = function () {
216	            var btn = document.getElementById('banner-copy-btn');
217	            var icon = document.getElementById('banner-copy-icon');
218	            var text = document.getElementById('banner-copy-text');
219	            navigator.clipboard.writeText(PROMPTS[currentLang]).then(function () {
220	                btn.classList.add('copied');
221	                icon.textContent = '✅';
222	                text.textContent = 'Copied!';
223	                setTimeout(function () {
224	                    btn.classList.remove('copied');
225	                    icon.textContent = '📋';
226	                    text.textContent = 'Copy Prompt';
227	                }, 2200);
228	            });
229	        };
230	
231	        init();
232	    })();
233	    </script>
234	
235	    <!-- Header -->
236	    <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 20px;">
237	        <div style="flex: 1;">
238	            <h1 style="font-size: 32px; font-weight: bold; margin: 0;">Vitaliy Hlynianyi-Zhuk</h1>
239	            <p style="font-size: 18px; margin: 5px 0 0 0;">AI Integration Engineer · Azure Cloud · Low-code Automation · Business Analyst · Scrum Master</p>
240	        </div>
